mapper.select:
SELECT * FROM lottery_result
WHERE lottery_type = #{type}
ORDER BY draw_num DESC
LIMIT #{limit} OFFSET #{offset}

SELECT * FROM lottery_result
ORDER BY draw_date DESC, draw_num DESC
LIMIT #{limit} OFFSET #{offset}

SELECT draw_num FROM lottery_result
WHERE lottery_type = #{type}
ORDER BY draw_num DESC LIMIT 1

SELECT * FROM lottery_result
WHERE lottery_type = #{type}
ORDER BY draw_num DESC LIMIT 1

SELECT * FROM lottery_result
WHERE lottery_type = #{type}
  AND draw_date >= #{startDate}
  AND draw_date <= #{endDate}
ORDER BY draw_num ASC

SELECT draw_num, draw_date, numbers FROM lottery_result
WHERE lottery_type = #{type}
ORDER BY draw_num ASC
